mapper.select:
SELECT ocbr.*,e.actual_name createUserName
FROM t_etc_balance_record ocbr
LEFT JOIN t_employee e on e.employee_id = ocbr.create_user_id


        AND (INSTR(ocbr.balance_record_no,#{queryForm.keyWords})
        or INSTR(e.actual_name,#{queryForm.keyWords})
        )


        AND ocbr.income_flag = #{queryForm.incomeFlag}



        and DATE_FORMAT(ocbr.create_time, '%Y-%m-%d') >= #{queryForm.createStartTime}


        and DATE_FORMAT(ocbr.create_time, '%Y-%m-%d') <= #{queryForm.createEndTime}




    ORDER BY ocbr.create_time DESC
